import{_ as a,o as i,c as n,ai as e}from"./chunks/framework.BIXs0jTs.js";const t="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"MCP 深度集成","description":"","frontmatter":{"title":"MCP 深度集成"},"headers":[],"relativePath":"30-mcp/deep-integration.md","filePath":"30-mcp/deep-integration.md","lastUpdated":null}'),l={name:"30-mcp/deep-integration.md"};function p(h,s,o,r,d,k){return i(),n("div",null,[...s[0]||(s[0]=[e('<h1 id="第-10-章-mcp-深度集成-连接企业级数据" tabindex="-1">第 10 章　MCP 深度集成：连接企业级数据 <a class="header-anchor" href="#第-10-章-mcp-深度集成-连接企业级数据" aria-label="Permalink to &quot;第 10 章　MCP 深度集成：连接企业级数据&quot;">​</a></h1><p><img src="'+t+`" alt="MCP 深度集成：连接企业级数据"></p><p>学会了写“Hello World”，现在我们要玩点真的。 在企业环境中，Claude Code 真正发挥价值的地方在于：<strong>它可以直接访问你现有的数据孤岛</strong>。</p><p>本章将通过三个进阶场景，展示如何将 MCP 集成到复杂的生产系统中：</p><ol><li><strong>数据库</strong>：直接用自然语言查询 SQL。</li><li><strong>API 网关</strong>：通过 OpenAPI 规范自动生成 Server。</li><li><strong>复杂状态</strong>：处理分页、认证和上下文依赖。</li></ol><h2 id="_10-1-场景一-连接-sqlite-postgresql-数据库" tabindex="-1">10.1 场景一：连接 SQLite/PostgreSQL 数据库 <a class="header-anchor" href="#_10-1-场景一-连接-sqlite-postgresql-数据库" aria-label="Permalink to &quot;10.1 场景一：连接 SQLite/PostgreSQL 数据库&quot;">​</a></h2><p>想象一下，你对 Claude 说：“帮我找出上周注册的所有活跃用户，并按地区统计分布。” 如果没有 MCP，你得自己写 SQL，导出 CSV，粘贴给 Claude。 有了 MCP，Claude 可以直接查库。</p><h3 id="_10-1-1-官方-sqlite-server" tabindex="-1">10.1.1 官方 SQLite Server <a class="header-anchor" href="#_10-1-1-官方-sqlite-server" aria-label="Permalink to &quot;10.1.1 官方 SQLite Server&quot;">​</a></h3><p>MCP 官方维护了一个 <code>sqlite</code> 参考实现。我们可以直接使用它，而无需重写代码。</p><p><strong>安装与配置</strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;my-db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;uvx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;mcp-server-sqlite&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;--db-path&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;/path/to/my/production.db&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><em>(注：<code>uvx</code> 是 Python 工具链 <code>uv</code> 的执行命令，可以快速运行 Python 包。你也可以用 <code>pipx</code> 或 <code>docker</code>)</em></p><h3 id="_10-1-2-安全性设计-readonly" tabindex="-1">10.1.2 安全性设计 (ReadOnly) <a class="header-anchor" href="#_10-1-2-安全性设计-readonly" aria-label="Permalink to &quot;10.1.2 安全性设计 (ReadOnly)&quot;">​</a></h3><p>你肯定不希望 Claude 不小心删了库。 <strong>最佳实践</strong>：</p><ul><li><strong>只读账号</strong>：为 MCP Server 创建一个专用的数据库用户，只授予 <code>SELECT</code> 权限。</li><li><strong>Schema 过滤</strong>：在 Server 代码中硬编码允许访问的表名列表，隐藏敏感表（如 <code>admin_users</code>, <code>secrets</code>）。</li></ul><hr><h2 id="_10-2-场景二-基于-openapi-swagger-自动生成" tabindex="-1">10.2 场景二：基于 OpenAPI (Swagger) 自动生成 <a class="header-anchor" href="#_10-2-场景二-基于-openapi-swagger-自动生成" aria-label="Permalink to &quot;10.2 场景二：基于 OpenAPI (Swagger) 自动生成&quot;">​</a></h2><p>你的公司可能有成百上千个微服务，每个都有 REST API。如果都要手写 MCP Server，那得累死。 好消息是：如果你的 API 有 OpenAPI (Swagger) 文档，你可以<strong>自动生成 MCP Server</strong>。</p><h3 id="_10-2-1-使用-fastmcp-或类似工具" tabindex="-1">10.2.1 使用 <code>fastmcp</code> 或类似工具 <a class="header-anchor" href="#_10-2-1-使用-fastmcp-或类似工具" aria-label="Permalink to &quot;10.2.1 使用 \`fastmcp\` 或类似工具&quot;">​</a></h3><p>社区已经涌现出许多“转换器”工具。以 Python 的 <code>fastmcp</code> 为例：</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fastmcp </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FastMCP</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接从 OpenAPI 文档 URL 创建 Server</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mcp </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> FastMCP.from_openapi(</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    url</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://api.my-company.com/openapi.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">    name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;company-api&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mcp.run()</span></span></code></pre></div><h3 id="_10-2-2-自动生成的局限性" tabindex="-1">10.2.2 自动生成的局限性 <a class="header-anchor" href="#_10-2-2-自动生成的局限性" aria-label="Permalink to &quot;10.2.2 自动生成的局限性&quot;">​</a></h3><p>自动生成的工具通常缺乏“语义”。</p><ul><li>API 里的 <code>GET /users/{id}</code> 可能参数叫 <code>id</code>，但 Claude 不知道这个 ID 是 UUID 还是自增整数。</li><li><strong>解决方案</strong>：在 OpenAPI 文档中完善 <code>description</code> 字段。Claude 会读取这些描述作为 Prompt 的一部分。</li></ul><hr><h2 id="_10-3-场景三-处理分页与长列表-pagination" tabindex="-1">10.3 场景三：处理分页与长列表 (Pagination) <a class="header-anchor" href="#_10-3-场景三-处理分页与长列表-pagination" aria-label="Permalink to &quot;10.3 场景三：处理分页与长列表 (Pagination)&quot;">​</a></h2><p>MCP 的一个常见挑战是：数据量太大，Token 不够用。 比如你问：“列出所有 Jira Ticket”，Server 如果直接返回 10000 条记录，Claude 的上下文窗口瞬间就爆了。</p><h3 id="_10-3-1-资源分页-resource-pagination" tabindex="-1">10.3.1 资源分页 (Resource Pagination) <a class="header-anchor" href="#_10-3-1-资源分页-resource-pagination" aria-label="Permalink to &quot;10.3.1 资源分页 (Resource Pagination)&quot;">​</a></h3><p>MCP 协议支持分页模式。 当 Claude 请求一个大资源时，Server 可以只返回前 100 条，并附带一个 <code>nextCursor</code>。 Claude Code 内部会自动处理这种分页逻辑（或者你可以明确告诉它“只读前 5 页”）。</p><h3 id="_10-3-2-摘要模式-summary-pattern" tabindex="-1">10.3.2 摘要模式 (Summary Pattern) <a class="header-anchor" href="#_10-3-2-摘要模式-summary-pattern" aria-label="Permalink to &quot;10.3.2 摘要模式 (Summary Pattern)&quot;">​</a></h3><p>与其返回原始数据，不如让 Server 先做一次“预处理”。 <strong>Bad Tool</strong>: <code>get_all_logs()</code> -&gt; 返回 100MB 文本。 <strong>Good Tool</strong>: <code>analyze_logs(keyword, time_range)</code> -&gt; Server 在本地 grep 后，只返回匹配的 50 行。</p><p><strong>设计原则</strong>：<strong>把计算留在 Server 端，把决策留给 Claude。</strong></p><hr><h2 id="_10-4-认证与鉴权-authentication" tabindex="-1">10.4 认证与鉴权 (Authentication) <a class="header-anchor" href="#_10-4-认证与鉴权-authentication" aria-label="Permalink to &quot;10.4 认证与鉴权 (Authentication)&quot;">​</a></h2><p>企业服务通常需要 API Key 或 OAuth Token。</p><h3 id="_10-4-1-环境变量注入" tabindex="-1">10.4.1 环境变量注入 <a class="header-anchor" href="#_10-4-1-环境变量注入" aria-label="Permalink to &quot;10.4.1 环境变量注入&quot;">​</a></h3><p>最简单的方式是通过环境变量传递密钥。 在 Claude Code 的配置文件中：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;index.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ghp_xxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_10-4-2-动态-oauth-human-in-the-loop" tabindex="-1">10.4.2 动态 OAuth (Human-in-the-loop) <a class="header-anchor" href="#_10-4-2-动态-oauth-human-in-the-loop" aria-label="Permalink to &quot;10.4.2 动态 OAuth (Human-in-the-loop)&quot;">​</a></h3><p>有些 Server 需要用户手动登录。 MCP 协议支持 Server 向 Host 发送“需要用户输入”的请求。 当 Server 启动时，它可以在日志中打印一个 URL：“请访问 <code>http://localhost:3000/auth</code> 进行登录”。用户在浏览器完成登录后，Server 获取 Token 并开始工作。</p><hr><h2 id="_10-5-小结" tabindex="-1">10.5 小结 <a class="header-anchor" href="#_10-5-小结" aria-label="Permalink to &quot;10.5 小结&quot;">​</a></h2><p>深度集成不仅仅是“调通 API”，更是对<strong>数据流向的设计</strong>。</p><ul><li>用 <strong>Read-Only 账号</strong> 保护数据库。</li><li>用 <strong>OpenAPI</strong> 批量接入微服务。</li><li>用 <strong>预处理</strong> 和 <strong>分页</strong> 解决 Token 瓶颈。</li></ul><p>掌握了这些，你就可以把 Claude Code 变成一个真正的“全栈工程师”——它左手查库，右手调接口，中间还能帮你写总结报告。</p><p>在下一章，我们将讨论最后一个关键话题：<strong>如何把这一切安全地部署到团队环境中</strong>。</p>`,46)])])}const E=a(l,[["render",p]]);export{g as __pageData,E as default};
